        self.strength = strength
        self.armor = armor
        self.level = level

    def is_defeated(self):
        return self.health <= 0

class Player(Character):
    def __init__(self):
        super().__init__(100, 10, 5)
        self.experience = 0
        self.upgrade_points = 0

    def level_up(self):
        self.level += 1
        self.upgrade_points += 1

    def use_upgrade_points(self):
        while self.upgrade_points > 0:
            print("Choose a stat to upgrade: ")
            print("1. Health")
            print("2. Strength")
            print("3. Armor")
            choices = {'1': 'health', '2': 'strength', '3': 'armor'}
            choice = input("> ")
            if choice in choices:
                getattr(self, f'upgrade_{choices[choice]}')()
                self.upgrade_points -= 1
            else:
                print("Invalid choice. Please choose 1, 2, or 3.")

    def upgrade_health(self):
        self.health += 20

    def upgrade_strength(self):
        self.strength += 3

    def upgrade_armor(self):
        self.armor += 1

    def add_experience(self, exp):
        self.experience += exp
        while self.experience >= 100:
            self.level_up()
            self.experience -= 100

class Enemy(Character):
    def __init__(self, level, is_boss=False):
        enemy_level = level if is_boss else random.randint(level, level + 2)
        multiplier = 5 if is_boss else 2
        super().__init__(enemy_level * 20, enemy_level * 2, enemy_level, level)
        self.is_boss = is_boss

def critical_hit():
    return random.randint(1, 10) == 1

def dodge():
    return random.randint(1, 10) <= 2

def fight(player, enemy):
    # ... (Функция боя не изменится)
    # Код функции боя не изменён, чтобы не раздувать пример.

def game():
    # ... (Функция запуска игры не изменится)
    # Код функции запуска игры не изменён, чтобы не раздувать пример.

if __name__ == "__main__":
    game()
